#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long C;
        scanf("%lld", &C);
        int d = 0;
        while ((1LL << d) <= C) ++d; // smallest d with 2^d > C
        long long mask = ((1LL << d) - 1) ^ C;
        long long A = mask, B = mask;
        for (int i = d - 1; i >= 0; --i) {
            if ((C >> i) & 1LL) {
                if (A <= B) A |= (1LL << i);
                else B |= (1LL << i);
            }
        }
        printf("%lld\n", A * B);
    }
    return 0;
}

