#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        C = int(next(it))
        d = 0
        while (1 << d) <= C:
            d += 1
        mask = ((1 << d) - 1) ^ C
        A = B = mask
        for i in range(d - 1, -1, -1):
            if (C >> i) & 1:
                if A <= B:
                    A |= (1 << i)
                else:
                    B |= (1 << i)
        out.append(str(A * B))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

